var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"헤헤, 이것 봐~ 역시 아이리 님이 나서면 간단하지~♪","JPN":"ヘヘ、これ見て～やっぱりアイリ様の手にかかれば簡単よ～♪","ENG":"Heh heh. Look at this. Irie can solve anything! ♪","TWN":"哈哈，看吧~~果然，艾莉一出手就知有沒有！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"일단 목숨은 건진 것 같네...... 모두 고생했어.","JPN":"とりあえず、命は助かったようだな……みんなご苦労だった。","ENG":"That was close. Everyone, good job.","TWN":"似乎是暫且保住了性命……大家都辛苦了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"적들의 전파공격이 단순한 신호방해에 그쳐서 다행이에요.","JPN":"敵の電波攻撃が単純な信号妨害程度でよかったです。","ENG":"I'm glad the enemy's electromagnetic wave attacks only jammed our signals.","TWN":"幸虧敵方的電波攻擊只是單純的信號干擾。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"이제 20분 정도면 현실세계로 부상할 수 있을 것 같아요.","JPN":"あと20分ほどすれば、ノーマルサイドに浮上できそうです。","ENG":"We've got only twenty minutes left until we'll be back into Normalside.","TWN":"大約20分鐘左右我們就能躍出至現世。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"정말이야?","JPN":"本当か？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"휴우...... 살았다......","JPN":"ふう……助かった……","ENG":"Whew, thank God!","TWN":"呼——活下來了……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"그런데 우리 싸우기 전에 말이야, 아이리와 뭘 확인해 봐야 한다고 하지 않았어?","JPN":"そうだ、戦う前にアイリと何か確認しないといけないって言ってなかったか？","ENG":"By the way, before we fought, you said Irie needed to see something. What is it?","TWN":"隊了，戰鬥前我們不是說要跟艾莉確認一下什麼的嗎?"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"응? 아이리 님 불렀어?","JPN":"何？　アイリ様を呼んだ？","ENG":"Mm? Did you call Irie?","TWN":"嗯？誰在叫艾莉？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"아, 그러고 보니......","JPN":"ああ、そういえば……","ENG":"Ah, that's right.","TWN":"啊，妳看… "},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"제나, 아이리.","JPN":"ジーナ、アイリ。","ENG":"Zena. Irie.","TWN":"珍娜、艾莉。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"혹시 이 영상 속 인물이 누군지...... 알아보겠어요?","JPN":"この映像の中の人物が誰なのか……わかりますか？","ENG":"Do you recognize this person in the video?","TWN":"妳們能夠認出...這段影片中的人物嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"이건...... 아이리잖아?","JPN":"これは……アイリじゃないか？","ENG":"It's... Irie.","TWN":"咦？這...這不是艾莉嗎?"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"응? 정말진짜? 아이리 님 언제 찍힌 거야?","JPN":"え？　本当？　アイリ様いつ撮られたの？","ENG":"Mm? It is Irie! When was Irie filmed?","TWN":"嗯？真的是耶？艾莉什麼時候拍到的？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"거기 정지! 곧 조회 시간인데 어딜 가는 거냐!","JPN":"そこ、止まれ！　もうすぐ朝礼の時間なのにどこに行くんだ！","ENG":"Hey, stop right there! It'll be a morning assembly soon. Where do you think you're going?","TWN":"停下來！就要開朝會了，妳這是要去哪裡!"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"아하하~♪ 그런 명령으론 아이리님의 스피드를 따라잡지 못할걸~♪","JPN":"あはは～♪　そんな命令ではアイリ様のスピードに追いつけないよ～♪","ENG":"Ah hah hah! ♪ Orders like that can't stop Irie! ♪","TWN":"啊哈哈哈~♪妳這種命令是追不上██大人的速度的~♪"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"몇 달만의 푸른 하늘이잖아? 이런 날 교실에 틀어박혀 있는 건 청춘에 대한 배신이라구~♪","JPN":"何か月ぶりの青空でしょ？\\nこんな日に教室に閉じこもるのは青春への裏切りだよ～♪","ENG":"I haven't seen such a blue sky for months. I'm too young to stay cooped up in a classroom on a beautiful day like this! ♪","TWN":"這麼多個月以來天空好不容易變得這麼藍，在這種日子窩在教室裡簡直背叛青春啊~~~"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"아이리 알포드...... 매일 옥상에서 학생회 허가도 받지 않고 폭죽놀이를 벌이는 무법자!","JPN":"アイリ・アルフォード……\\n毎日屋上で生徒会の許可も取らずに花火で遊ぶ無法者！","ENG":"Irie Alford. You're the outlaw who plays with fireworks every day on the rooftop, without the Student Council's permission!","TWN":"艾莉·阿爾伯特……未經學生會許可，每天在頂樓隨意施放煙火的非法之徒！"},"stage":{"bg":"SCHOOL_SPRING","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};